class Node<T> {
  T data;
  Node<T>? next;

  Node(this.data);
}

class LinkedList<T> {
  Node<T>? head;
  int _length = 0;

  int get length => _length;
  bool get isEmpty => head == null;

  // Insert at end - O(n)
  void append(T data) {
    final newNode = Node(data);
    if (head == null) {
      head = newNode;
    } else {
      var current = head;
      while (current!.next != null) {
        current = current.next;
      }
      current.next = newNode;
    }
    _length++;
  }

  // Insert at beginning - O(1)
  void prepend(T data) {
    final newNode = Node(data);
    newNode.next = head;
    head = newNode;
    _length++;
  }

  // Delete by value - O(n)
  bool delete(T data) {
    if (head == null) return false;

    if (head!.data == data) {
      head = head!.next;
      _length--;
      return true;
    }

    var current = head;
    while (current!.next != null) {
      if (current.next!.data == data) {
        current.next = current.next!.next;
        _length--;
        return true;
      }
      current = current.next;
    }
    return false;
  }

  // Search - O(n)
  bool contains(T data) {
    var current = head;
    while (current != null) {
      if (current.data == data) return true;
      current = current.next;
    }
    return false;
  }

  @override
  String toString() {
    var result = <T>[];
    var current = head;
    while (current != null) {
      result.add(current.data);
      current = current.next;
    }
    return result.toString();
  }
}

// Usage
var list = LinkedList<int>();
list.append(1);
list.append(2);
list.prepend(0);
print(list); // [0, 1, 2]
print(list.contains(1)); // true
list.delete(1);
print(list); // [0, 2]
